## Descriptors: Property Access as Operators

```python
# Descriptors intercept attribute access: obj.attr calls __get__, __set__, __delete__
class Validated:
    """Descriptor that validates values on assignment"""
    def __init__(self, min_val, max_val):
        self.min_val = min_val
        self.max_val = max_val
        self.name = None

    def __set_name__(self, owner, name):
        self.name = name  # called when class is defined

    def __get__(self, obj, objtype=None):
        if obj is None: return self  # accessed on class itself
        return getattr(obj, f'_{self.name}', None)

    def __set__(self, obj, value):
        if not (self.min_val <= value <= self.max_val):
            raise ValueError(f'{self.name}={value} out of range [{self.min_val}, {self.max_val}]')
        setattr(obj, f'_{self.name}', value)

class Temperature:
    celsius = Validated(-273.15, 1e6)  # descriptor instance

    def __init__(self, c: float):
        self.celsius = c  # calls Validated.__set__

t = Temperature(100)
print(t.celsius)  # 100
t.celsius = -300  # raises ValueError: celsius=-300 out of range
```

## Expression Trees: Building DSLs with Operators

```python
# SQLAlchemy-style expression builder — operators return AST nodes
from __future__ import annotations
from dataclasses import dataclass, field
from typing import Any

@dataclass
class Expr:
    def __and__(self, other: Expr) -> AndExpr:
        return AndExpr(self, other)

    def __or__(self, other: Expr) -> OrExpr:
        return OrExpr(self, other)

    def __invert__(self) -> NotExpr:
        return NotExpr(self)

@dataclass
class Column(Expr):
    name: str

    def __eq__(self, other: Any) -> EqExpr:    # type: ignore
        return EqExpr(self, other)

    def __gt__(self, other: Any) -> GtExpr:
        return GtExpr(self, other)

    def __lt__(self, other: Any) -> LtExpr:
        return LtExpr(self, other)

@dataclass
class EqExpr(Expr): left: Column; right: Any
@dataclass  
class GtExpr(Expr): left: Column; right: Any
@dataclass
class LtExpr(Expr): left: Column; right: Any
@dataclass
class AndExpr(Expr): left: Expr; right: Expr
@dataclass
class OrExpr(Expr): left: Expr; right: Expr
@dataclass
class NotExpr(Expr): operand: Expr

def compile_to_sql(expr: Expr) -> str:
    match expr:
        case EqExpr(Column(n), v): return f"{n} = {v!r}"
        case GtExpr(Column(n), v): return f"{n} > {v!r}"
        case LtExpr(Column(n), v): return f"{n} < {v!r}"
        case AndExpr(l, r): return f"({compile_to_sql(l)}) AND ({compile_to_sql(r)})"
        case OrExpr(l, r): return f"({compile_to_sql(l)}) OR ({compile_to_sql(r)})"
        case NotExpr(e): return f"NOT ({compile_to_sql(e)})"

age = Column('age')
status = Column('status')

expr = (age > 18) & (status == 'active') | ~(age < 65)
print(compile_to_sql(expr))
# ((age > 18) AND (status = 'active')) OR (NOT (age < 65))
```

## Metaclass Operators

```python
# Operators can be defined on metaclasses, affecting class-level expressions
class ModelMeta(type):
    def __or__(cls, other: type) -> type:
        """Allow Model | OtherModel for union types in schema definitions"""
        return type(f'{cls.__name__}|{other.__name__}', (cls, other), {})

    def __getitem__(cls, item):
        """Allow Model[param] for generic-style parameterisation"""
        return type(f'{cls.__name__}[{item}]', (cls,), {'__param__': item})

class Model(metaclass=ModelMeta): pass
class UserModel(Model): pass
class AdminModel(Model): pass

Combined = UserModel | AdminModel  # uses metaclass __or__
print(Combined.__name__)  # UserModel|AdminModel
```
